import java.io.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String userInput = reader.readLine();

        // Properly sanitizing and encoding user input
        String encodedUserInput = Encode.forHtml(userInput);

        String welcomeMessage = "Hello, " + encodedUserInput + "! Welcome to our website.";

        System.out.println(welcomeMessage);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
